                'prompt' => NULL,
                'skills' => '["ikhlas"]',
                'slug' => 'siapa-meninggalkan-jejak-emas-di-pantai',
                'sort_order' => 0,
                'status' => 'approved',
                'title' => 'Siapa Meninggalkan Jejak Emas di Pantai?',
                'type' => 'storytelling',
