            [
                'active' => 1,
                'addon_id' => NULL,
                'agama' => '[]',
                'ages' => '[4,5,6,7,8,9,10]',
                'created_by' => 1,
                'creator' => 'admin',
                'data' => '{"pages": [{"num": 1, "text": "Di sebuah pulau besar yang terpencil, hiduplah dua raksasa perkasa: Godzilla dan King Kong."}, {"num": 2, "text": "Mereka sudah lama menjadi musuh bebuyutan. Setiap bertemu, pasti langsung berkelahi tanpa alasan yang jelas."}, {"num": 3, "text": "Godzilla merasa dialah penguasa lautan, sedangkan King Kong menganggap dialah raja di daratan dan gunung."}, {"num": 4, "text": "Mereka saling menghina dan menyimpan rasa benci. Dendam terus tumbuh di hati keduanya."}, {"num": 5, "text": "Setelah bertarung, mereka pergi dengan rasa marah dan berjanji akan mengalahkan satu sama lain lain kali."}, {"num": 6, "text": "Penghuni hutan dan hewan-hewan lain merasa takut dan tidak tenang karena sering terjadi gempa dan kerusakan saat mereka berantem."}, {"num": 7, "text": "Suatu hari, datanglah bahaya besar. Seekor makhluk asing yang lebih kuat dan ganas menyerang pulau itu."}, {"num": 8, "text": "Makhluk itu menghancurkan pepohonan dan mengusir semua hewan. Semua ketakutan dan tidak tahu harus berbuat apa."}, {"num": 9, "text": "Godzilla mencoba melawannya sendirian, tapi ia kewalahan dan terluka parah."}, {"num": 10, "text": "King Kong juga mencoba melawan, tapi tenaganya tidak cukup untuk mengalahkan musuh yang lebih besar itu."}, {"num": 11, "text": "Keduanya terbaring lemah. Saat itu, mereka sadar: selama ini kekuatan mereka terbuang hanya untuk berkelahi satu sama lain."}, {"num": 12, "text": "King Kong berkata, “Jika kita terus bermusuhan, pulau ini akan hancur dan kita akan kalah.” Godzilla pun mengangguk setuju."}, {"num": 13, "text": "Mereka memutuskan untuk mengesampingkan dendam, saling memaafkan, dan bekerja sama."}, {"num": 14, "text": "Dengan kekuatan yang digabungkan, mereka akhirnya bisa mengusir makhluk asing itu dan menyelamatkan pulau tempat mereka tinggal."}, {"num": 15, "text": "Sejak hari itu, mereka tidak lagi berkelahi. Mereka menjadi teman yang saling menjaga, dan mengajarkan bahwa memaafkan lebih baik daripada terus memendam benci."}]}',
                'desc' => 'Dua raksasa yang selalu bermusuhan dan berkelahi. Sampai suatu bahaya datang, mereka sadar bahwa memaafkan dan bersatu jauh lebih baik daripada terus bermusuhan.',
                'id' => 1041,
                'image' => 'cover.png',
                'moral' => 'Jangan memendam dendam selamanya. Memaafkan lebih baik daripada terus bermusuhan. Persatuan membawa kekuatan, sedangkan perselisihan hanya membawa kerugian.',
                'notes' => NULL,
                'plans' => NULL,
                'prompt' => NULL,
                'skills' => '["memaafkan", "tidak_pendendam"]',
                'slug' => 'godzilla-vs-king-kong',
                'sort_order' => 0,
                'status' => 'approved',
                'title' => 'Godzilla vs King Kong',
                'type' => 'storytelling',
