                'agama' => '[]',
                'ages' => '[3,4,5,6,7,8,9,10]',
                'created_by' => 1,
                'creator' => 'admin',
                'data' => '{
  "pages": [
    {"num": 1, "text": "Di kebun tumbuh banyak buah dan sayur. Ada jambu, mangga, melon, dan tomat kecil."},
    {"num": 2, "text": "Tomat melihat buah lain terlihat besar dan manis. Ia merasa dirinya kecil saja."},
    {"num": 3, "text": "Ia berkata pelan, "Aku hanya kecil, rasanya agak asam. Tidak seindah buah lain.""},
    {"num": 4, "text": "Suatu hari, Pak Tani datang memetik semua tanaman yang sudah matang."},
    {"num": 5, "text": "Ia juga memetik tomat dan memasukkannya ke dalam keranjang."},
    {"num": 6, "text": "Di dapur, Ibu mencuci tomat itu sampai bersih."},
    {"num": 7, "text": "Ibu memotong tomat dan memasukkannya ke dalam sayur bening."},
    {"num": 8, "text": "Sayur itu jadi terlihat segar dan rasanya lebih enak."},
    {"num": 9, "text": "Ibu juga membuat sambal dan salad, semuanya pakai tomat."},
    {"num": 10, "text": "Anak-anak makan dengan lahap dan berkata, "Wah enak sekali!""},
    {"num": 11, "text": "Tomat mendengar itu dan tersenyum. "Ternyata aku juga berguna," pikirnya."},
    {"num": 12, "text": "Ia sadar Tuhan menciptakannya dengan kebaikan sendiri."},
    {"num": 13, "text": "Ia tidak lagi merasa kurang. Ia senang bisa membantu masakan jadi lebih nikmat."},
    {"num": 14, "text": "Semua tanaman di kebun juga menyukai tomat yang kini tenang dan senang."},
    {"num": 15, "text": "Sejak itu, tomat selalu bersyukur atas apa yang dimilikinya."}
  ]
}',
                'desc' => 'Tomat kecil awalnya merasa tidak sebaik buah lain, lalu sadar ia punya manfaat yang baik untuk masakan dan tubuh.',
