                'data' => '{
  "pages": [
    {"num": 1, "text": "Di dalam tas sekolah Budi ada sebuah buku catatan yang rapi."},
    {"num": 2, "text": "Suatu hari Budi ingin meminjam penghapus dari teman."},
    {"num": 3, "text": "Ia berkata dengan nada kasar, "Hei, kasih penghapusmu!""},
    {"num": 4, "text": "Temannya tidak senang dan tidak mau meminjamkannya."},
    {"num": 5, "text": "Budi bingung. Ia memegang bukunya yang terasa lembut di tangannya."},
    {"num": 6, "text": "Ia merasa seolah mendengar, "Coba bicara dengan kata yang lebih baik.""},
    {"num": 7, "text": "Keesokan harinya Budi mencoba lagi, "Permisi, boleh pinjam penghapusmu? Terima kasih.""},
    {"num": 8, "text": "Temannya tersenyum dan segera memberikannya."},
    {"num": 9, "text": "Setelah selesai, Budi mengembalikan sambil berkata, "Terima kasih banyak ya.""},
    {"num": 10, "text": "Suatu hari ia tidak sengaja menjatuhkan buku milik teman."},
    {"num": 11, "text": "Ia segera mengambilnya dan berkata, "Maaf ya, aku tidak hati-hati.""},
    {"num": 12, "text": "Temannya menjawab, "Tidak apa-apa, asalkan kamu jujur.""},
    {"num": 13, "text": "Budi jadi mengerti, kata sopan tidak butuh biaya tapi hasilnya indah."},
    {"num": 14, "text": "Ia selalu mengucapkan permisi, terima kasih, dan maaf setiap hari."},
    {"num": 15, "text": "Sekarang Budi punya banyak teman dan disukai semua orang di sekolah."}
